#include <cstdlib>
#include <cstring>
#include <iostream>
#include <thrust/device_vector.h>
#include <cub/device/device_reduce.cuh>
#include <nvtx3/nvToolsExt.h>
#include "add.h"

void run_correctness_test() {
  const int num_items = 1 << 14;
  thrust::device_vector<int> in(num_items, 1);
  thrust::device_vector<int> out(1);

  add(num_items, in.data().get(), out.data().get());

  if (out[0] != num_items) {
    std::cerr << "Test failed!" << std::endl;
    std::exit(1);
  }
}

void run_benchmark() {
  const int num_items = 1 << 26;
  thrust::device_vector<int> in(num_items, 1);
  thrust::device_vector<int> out(1);

  const int warmup_iters = 3;
  const int timed_iters = 100;

  for (int i = 0; i < warmup_iters; i++) {
    add(num_items, in.data().get(), out.data().get());
  }
  cudaDeviceSynchronize();

  nvtxRangePushA("bench_region");
  for (int i = 0; i < timed_iters; i++) {
    add(num_items, in.data().get(), out.data().get());
  }
  cudaDeviceSynchronize();
  nvtxRangePop();
}

int main(int argc, char* argv[]) {
  if (argc > 1 && std::strcmp(argv[1], "--perf") == 0) {
    run_benchmark();
  } else {
    run_correctness_test();
  }
  return 0;
}

