static void run_correctness() {
  thrust::device_vector<int> in{ 1, 4, 0, 3 };
  thrust::device_vector<int> out(in.size());

  sort(in.size(), in.data().get(), out.data().get());

  if (out[0] != 0 || out[1] != 1 || out[2] != 3 || out[3] != 4) {
    std::cerr << "Test failed!" << std::endl;
    std::exit(1);
  }
}

static void run_benchmark() {
  const int N = 10'000'000;
  const int warmup_iters = 3;
  const int timed_iters = 100;

  std::vector<int> h_in(N);
  for (int i = 0; i < N; i++) {
    h_in[i] = static_cast<int>((static_cast<unsigned>(i) * 2654435761u) ^ 0xdeadbeef);
  }

  thrust::device_vector<int> d_in(h_in.begin(), h_in.end());
  thrust::device_vector<int> d_out(N);

  for (int i = 0; i < warmup_iters; i++) {
    sort(N, d_in.data().get(), d_out.data().get());
  }
  cudaDeviceSynchronize();

  nvtxRangePushA("bench_region");
  for (int i = 0; i < timed_iters; i++) {
    sort(N, d_in.data().get(), d_out.data().get());
  }
  cudaDeviceSynchronize();
  nvtxRangePop();
}

int main(int argc, char* argv[]) {
  bool perf = false;
  for (int i = 1; i < argc; i++) {
    if (std::strcmp(argv[i], "--perf") == 0) {
      perf = true;
    }
  }

  if (perf) {
    run_benchmark();
  } else {
    run_correctness();
  }
  return 0;
}

