#include "kernel.h"
#include <cuda_runtime_api.h>
#include <cstdlib>
#include <cstring>
#include <iostream>
#include <nvtx3/nvToolsExt.h>

int main(int argc, char **argv) {
  bool perf = false;
  for (int i = 1; i < argc; ++i) {
    if (std::strcmp(argv[i], "--perf") == 0) perf = true;
  }

  int *d_data{};
  cudaMalloc(&d_data, sizeof(int));
  cudaMemset(d_data, 0, sizeof(int));

  const int threads = 64;
  const int blocks = 42;

  kernel<<<blocks, threads>>>(d_data);

  int result;
  cudaMemcpy(&result, d_data, sizeof(int), cudaMemcpyDeviceToHost);

  if (result != blocks * threads) {
    std::cerr << "Test failed!" << std::endl;
    std::exit(1);
  }

  if (perf) {
    const int perf_blocks = 4096;
    const int perf_threads = 256;
    const int warmup_iters = 3;
    const int timed_iters = 100;

    for (int i = 0; i < warmup_iters; ++i) {
      cudaMemset(d_data, 0, sizeof(int));
      kernel<<<perf_blocks, perf_threads>>>(d_data);
    }
    cudaDeviceSynchronize();

    nvtxRangePushA("bench_region");
    for (int i = 0; i < timed_iters; ++i) {
      cudaMemset(d_data, 0, sizeof(int));
      kernel<<<perf_blocks, perf_threads>>>(d_data);
    }
    cudaDeviceSynchronize();
    nvtxRangePop();
  }

  cudaFree(d_data);
  return 0;
}

