int main(int argc, char** argv) {
    const thrust::device_vector<int> in{1, 4, 0};
    thrust::device_vector<int> out = scan(in);

    if (out[0] != 0 || out[1] != 1 || out[2] != 5)
    {
        std::cerr << "Test failed!" << std::endl;
        std::exit(1);
    }

    bool perf = false;
    for (int i = 1; i < argc; ++i) {
        if (std::strcmp(argv[i], "--perf") == 0) perf = true;
    }

    if (perf) {
        const int N = 16 * 1024 * 1024;
        std::vector<int> h_in(N);
        for (int i = 0; i < N; ++i) h_in[i] = i % 7;
        thrust::device_vector<int> d_in(h_in.begin(), h_in.end());

        const int warmup = 3;
        const int iters = 100;

        for (int i = 0; i < warmup; ++i) {
            thrust::device_vector<int> tmp = scan(d_in);
        }
        cudaDeviceSynchronize();

        for (int i = 0; i < iters; ++i) {
            thrust::device_vector<int> tmp = scan(d_in);
        }
        cudaDeviceSynchronize();
    }

    return 0;
}

